{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Household income cannot exceed 200% of the federal poverty level. 2024 Guidelines: 1: $30,120; 2: $40,880; 3: $51,640; 4: $62,400; 5: $73,160; 6: $83,920; 7: $94,680; 8: $105,440; each additional: +$10,760.[1]",
    "asset_limits": "No asset limits mentioned in program guidelines.[1][2][3]",
    "other_requirements": [
      "LIHEAP clients are automatically eligible.[1][2]",
      "Households may receive services only once unless weatherized more than 15 years ago.[1]",
      "Applies to owners or renters in single-family homes, mobile homes, or apartments.[2][4]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Energy efficiency improvements including insulation, caulking, weather-stripping, furnace and moisture repairs, addressing health/safety issues like air infiltration and heat loss; determined by professional home energy assessment; no specific dollar amounts or hours stated; repairs only if they support weatherization measures with SIR over 1 (no general rehab, cosmetics, or low-payback like mobile home skirting).[1][2][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Online: Complete questions at https://www.commerce.nd.gov/community-services/low-income-programs/weatherization-assistance (forwards to regional Community Action Agency).[1]",
      "Phone: State Weatherization Program Manager Alyssa Kroshus at (701) 328-5341; or regional CAP offices (e.g., Region I: 701-572-8191).[1]",
      "Regional CAP agencies handle intake (see geography.offices_or_providers).[1]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not specified; funds allocated to CAP agencies based on availability, continuation contingent on federal funding and performance.[3]",
    "forms": ["Online application questions (no specific form name/number listed).[1]"],
    "documents": ["Income documentation for all household members; LIHEAP approval if applicable (automatic eligibility).[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available through 8 regional Community Action Agencies covering all counties.[1]",
    "regional_variations": "Administered by local CAP agencies with potential differences in processing, providers, and wait times by region (e.g., Region I: Divide/Williams/McKenzie); contact regional CAP for specifics.[1]",
    "offices_or_providers": [
      "Region I (Divide, Williams, McKenzie): 701-572-8191[1]",
      "Other regions via 8 CAP agencies; full list at https://www.commerce.nd.gov/community-services/low-income-programs/weatherization-assistance[1]"
    ]
  },
  "official_source": "https://www.commerce.nd.gov/community-services/low-income-programs/weatherization-assistance",
  "gotchas": [
    "Services limited to one-time per household unless >15 years since prior weatherization; no general home repairs, cosmetics, or low-SIR measures.[1]",
    "Must contact regional CAP after state application; eligibility uses DOE or LIHEAP criteria interchangeably.[1][3]",
    "Income based on 200% FPL (higher than some programs' 60% state median, e.g., certain rehab).[1][5]",
    "Priority for LIHEAP clients; funded by DOE/LIHEAP with potential funding limits.[3]"
  ],
  "data_shape_notes": "Administered statewide via 8 regional CAP agencies; automatic eligibility for LIHEAP; 200% FPL income table scales by household size; one-time service rule with 15-year reweatherization exception."
}

{
  "name": "Older Adult Nutrition Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No means test or specific income limits; services targeted to those with greatest economic need but open to all 60+ regardless of income[1].",
    "asset_limits": "No asset limits or tests mentioned[1].",
    "other_requirements": ["Priority to rural residents, greatest economic/social need, severe disabilities, limited English proficiency[1]", "Spouses of any age eligible[1][3]", "Disabled persons under 60 residing in congregate sites or with eligible participants, only if it does not deprive 60+ participants[1][3]", "Home-delivered meals require homebound status due to physical incapacity, mental/social conditions, isolation, limited mobility, or remote location[3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Congregate meals in social/group settings; home-delivered meals for homebound seniors; each meal provides at least 1/3 of recommended dietary allowances per Dietary Guidelines for Americans and Dietary Reference Intakes; voluntary contributions requested but no one denied for inability to pay[1][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Aging Services Provider or Area Agency on Aging; regional variations apply (e.g., Morton County Council on Aging for local sites)[3]", "No statewide phone or URL specified in sources; eligibility determined locally (e.g., Nutrition Coordinator at Morton County Council on Aging)[3]"],
    "processing_time": "Not specified; annual redetermination for home-delivered meals[3]",
    "waitlist": "Not mentioned; meals for under 60 only if no deprivation of 60+ slots, implying potential capacity limits[3]",
    "forms": ["No specific form names/numbers identified"],
    "documents": ["Not explicitly listed; prepare proof of age, homebound status if applicable, and voluntary contribution if able[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available through local providers across North Dakota[1]",
    "regional_variations": "Administered by local councils on aging or senior centers (e.g., Morton County Council on Aging); homebound determination by local Nutrition Coordinator; potential differences in sites, availability, wait times by county/rural areas[1][3]",
    "offices_or_providers": ["Local Aging Services Providers, Area Agencies on Aging, senior centers (e.g., Morton County Council on Aging in Mandan)[1][3]"]
  },
  "official_source": "No single primary .gov URL identified; see https://ndseniorservices.org/Feeding%20Grandma.pdf (ND Senior Service Providers) and local HHS or Aging offices[1]",
  "gotchas": ["No income test but priority to highest need, so low-income/rural may get served first[1]", "Under 60 eligibility very limited and secondary to 60+ participants[1][3]", "Home-delivered requires proof of homebound status, not just age[3]", "Voluntary contributions expected but not mandatory[1][3]", "Often confused with SNAP or CSFP which have strict income limits[2][7]"],
  "data_shape_notes": "No income/asset test; priority-based targeting; locally administered with homebound criteria for delivery; open to spouses/under 60 in limited cases; rural focus[1][3]"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income must not exceed 125% of federal poverty level. North Dakota specific maximum annual income levels (before taxes): Household of 1: $19,563; Household of 2: $24,638; Household of 3: $33,313; Household of 4: $40,188. Levels increase for larger households.[3]",
    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Unemployed", "Have barriers to employment (e.g., low employment prospects)", "Priority given to: veterans and qualified spouses, individuals over 65, those with disabilities, low literacy or limited English proficiency, rural residents, homeless or at-risk, or those who failed to find employment via American Job Centers.[1][2][4]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work training (average 20 hours/week) at non-profit/public sites (e.g., childcare centers, schools, hospitals, senior centers); paid highest of federal/state/local minimum wage; on-the-job training; annual physical examinations; job-related counseling; assistance to transition to unsubsidized employment.[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone or contact: North Dakota HHS Vocational Rehabilitation at https://www.hhs.nd.gov/vr/scsep (specific phone not listed; statewide Job Service ND resources at https://www.jobsnd.com/job-seeker/resources-assistance); national SCSEP help line: 1-877-872-5627 (1-877-US2-JOBS); CareerOneStop Older Worker Program Finder.[1][2][3]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not specified; potential due to limited slots as grant-funded program.",
    "forms": ["No specific form names/numbers listed."],
    "documents": ["Proof of age, income verification (e.g., tax returns, pay stubs), unemployment status; prepare household size and income details.[3]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to specific counties: Bowman, Burleigh, Cass, Dunn, Grand Forks, McKenzie, Mountrail, Richland, Stark, Traill, Ward, Williams (12-14 counties total; sources vary slightly).[3][9]",
    "regional_variations": "Administered via two federal grants through state providers (e.g., HHS Vocational Rehabilitation); no detailed differences by region noted, but coverage not statewide.[1][3]",
    "offices_or_providers": ["North Dakota HHS Vocational Rehabilitation (https://www.hhs.nd.gov/vr/scsep); Job Service North Dakota (https://www.jobsnd.com).[1][3]"]
  },
  "official_source": "https://www.hhs.nd.gov/vr/scsep",
  "gotchas": ["Not statewide—only select counties, excluding many rural areas outside listed 12-14; income based on household size at 125% poverty level (use current HHS guidelines as listed figures may update annually); must be unemployed and seeking training bridge to private employment, not full-time jobs directly; priority tiers may create wait times; no asset test but barriers to employment required.[1][2][3]"],
  "data_shape_notes": "County-restricted to 12-14 specific counties; income table scales by household size; priority enrollment tiers; grant-funded with limited slots via state VR provider."
}

{
  "name": "Long-Term Care Ombudsman Services",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all qualifying residents regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must reside in a participating long-term care facility in North Dakota, including basic care facility, nursing home, assisted living facility, or swing bed hospital."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free and confidential services including: education on resident rights, service options, and regulations; support to resolve complaints on quality of care/services, quality of life, rights violations, access to services, transfer/discharge/eviction; promotion of resident/family/community involvement; identification of systems issues and advocacy for change.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1.855.462.5465 option 3 or 701.328.4617 (TTY: 711)", "Mail/In-person: State Long-Term Care Ombudsman, Adult and Aging Services, 1237 W. Divide Ave., Ste 6, Bismarck, ND 58501", "Referrals accepted from residents, families/friends, community members, facility staff, agencies/providers—no formal application form required"],
    "processing_time": "No formal processing; ombudsman responds to concerns as submitted, typically through visits and advocacy.",
    "waitlist": null,
    "forms": ["No specific forms required; consent from resident/resident representative needed for active advocacy"],
    "documents": ["No documents needed to initiate contact; resident consent may be requested to verify and proceed with complaint resolution"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in basic care facilities, nursing homes, assisted living facilities, or swing bed hospitals across North Dakota.",
    "regional_variations": "Program operates statewide from central office with ombudsmen conducting visits throughout the state; no specified differences in services, wait times, or providers by region.",
    "offices_or_providers": ["Primary office: 1237 W. Divide Ave., Ste 6, Bismarck, ND 58501"]
  },
  "official_source": "https://www.hhs.nd.gov/sites/www/files/documents/New%20LTCOP%20Brochure%202023%20v4%20(1).pdf",
  "gotchas": ["Services are for current residents of qualifying facilities only—not for admission assistance or non-residents; requires resident consent for active advocacy; not a regulatory or enforcement body but an independent advocate partnering with residents to resolve issues; anyone can refer a concern, but ombudsman verifies it exists before proceeding."],
  "data_shape_notes": "no income/asset/age test; open to all residents in specified facility types statewide; advocacy-based rather than financial or direct service provision; consent-driven and resident-directed"
}

